    41→import { ToolMaestroSelectionDialog } from './tool-maestro-selection-dialog';
    42→import type { Maestro } from '@/types';
    43→
    44→interface MindmapNode {
    45→  id: string;
    46→  label: string;
    47→  children?: MindmapNode[];
    48→  icon?: string;
    49→  color?: string;
    50→}
    51→
    52→interface MindmapsViewProps {
