   342→              <input
   343→                type="file"
   344→                accept=".json,.md,.markdown,.mm,.xmind,.txt"
   345→                onChange={handleImport}
   346→                className="hidden"
   347→              />
   348→            </label>
   349→          </Button>
   350→        </div>
   351→      </div>
   352→
   353→      {/* Info card */}
