   359→            </div>
   360→            <div>
   361→              <h3 className="font-semibold text-blue-900 dark:text-blue-100 mb-1">
   362→                Come funzionano le Mappe Mentali?
   363→              </h3>
   364→              <p className="text-sm text-blue-800 dark:text-blue-200">
   365→                Durante le lezioni con i professori, chiedi di creare una mappa mentale su qualsiasi argomento.
   366→                Le mappe appariranno qui automaticamente e potrai stamparle o scaricarle per studiare offline.
   367→              </p>
   368→            </div>
   369→          </div>
   370→        </CardContent>
   371→      </Card>
   372→
   373→      {/* Mindmaps grid */}
   374→      {loading ? (
   375→        <Card className="p-12">
   376→          <div className="text-center">
   377→            <Loader2 className="w-16 h-16 mx-auto text-slate-400 mb-4 animate-spin" />
   378→            <h3 className="text-xl font-semibold text-slate-900 dark:text-white mb-2">
   379→              Caricamento...
   380→            </h3>
   381→          </div>
   382→        </Card>
   383→      ) : mindmaps.length === 0 ? (
   384→        <Card className="p-12">
