   928→  // ARCHIVE SEARCH TOOL (Issue #37: Unified Archive Access for Maestri)
   929→  // ============================================================================
   930→  {
   931→    type: 'function',
   932→    name: 'search_archive',
   933→    description:
   934→      'Cerca materiali salvati nell\'archivio dello studente (mappe mentali, quiz, flashcard, riassunti, demo, compiti). Usa quando lo studente chiede "hai salvato...", "mostrami quella mappa...", "rivediamo il quiz di...".',
   935→    parameters: {
   936→      type: 'object',
   937→      properties: {
   938→        query: {
   939→          type: 'string',
   940→          description: 'Testo da cercare nei titoli e contenuti',
   941→        },
   942→        toolType: {
   943→          type: 'string',
   944→          enum: ['mindmap', 'quiz', 'flashcard', 'summary', 'demo', 'homework', 'diagram', 'timeline'],
   945→          description: 'Tipo di materiale da cercare (opzionale)',
   946→        },
   947→        subject: {
   948→          type: 'string',
   949→          description: 'Materia dei materiali (opzionale)',
   950→        },
   951→      },
   952→      required: [],
   953→    },
   954→  },
   955→];
   956→
   957→// ============================================================================
   958→// MINDMAP MODIFICATION COMMAND HELPERS
   959→// ============================================================================
   960→
   961→/**
   962→ * List of mindmap modification command names.
   963→ */
   964→const MINDMAP_MODIFICATION_COMMANDS = [
   965→  'mindmap_add_node',
   966→  'mindmap_connect_nodes',
   967→  'mindmap_expand_node',
   968→  'mindmap_delete_node',
   969→  'mindmap_focus_node',
   970→  'mindmap_set_color',
   971→] as const;
   972→
   973→/**
   974→ * Check if a tool name is a mindmap modification command.
   975→ */
   976→export function isMindmapModificationCommand(name: string): boolean {
   977→  return MINDMAP_MODIFICATION_COMMANDS.includes(name as typeof MINDMAP_MODIFICATION_COMMANDS[number]);
   978→}
   979→
   980→// ============================================================================
   981→// SUMMARY MODIFICATION COMMAND HELPERS (#70 Real-time Summary Tool)
   982→// ============================================================================
   983→
   984→/**
   985→ * List of summary modification command names.
   986→ */
   987→const SUMMARY_MODIFICATION_COMMANDS = [
   988→  'summary_set_title',
   989→  'summary_add_section',
   990→  'summary_add_point',
   991→  'summary_finalize',
   992→  'student_summary_add_comment', // #70 maieutic method
   993→] as const;
   994→
   995→/**
   996→ * Check if a tool name is a summary modification command.
   997→ */
   998→export function isSummaryModificationCommand(name: string): boolean {
   999→  return SUMMARY_MODIFICATION_COMMANDS.includes(name as typeof SUMMARY_MODIFICATION_COMMANDS[number]);
  1000→}
  1001→
  1002→// ============================================================================
  1003→// ONBOARDING COMMAND HELPERS (#61 Onboarding Voice Integration)
  1004→// ============================================================================
  1005→
  1006→/**
  1007→ * List of onboarding command names.
  1008→ */
  1009→const ONBOARDING_COMMANDS = [
  1010→  'set_student_name',
  1011→  'set_student_age',
  1012→  'set_school_level',
  1013→  'set_learning_differences',
  1014→  'set_student_gender',
  1015→  'confirm_step_data',
  1016→  'next_onboarding_step',
  1017→  'prev_onboarding_step',
  1018→] as const;
  1019→
  1020→/**
  1021→ * Check if a tool name is an onboarding command.
  1022→ */
  1023→export function isOnboardingCommand(name: string): boolean {
  1024→  return ONBOARDING_COMMANDS.includes(name as typeof ONBOARDING_COMMANDS[number]);
  1025→}
  1026→
  1027→// ============================================================================
  1028→// TOOL NAME TO TYPE MAPPING
  1029→// ============================================================================
  1030→
  1031→/**
  1032→ * Maps voice tool names to ToolType.
  1033→ */
  1034→export function getToolTypeFromName(name: string): ToolType | null {
  1035→  switch (name) {
  1036→    case 'create_mindmap':
  1037→      return 'mindmap';
  1038→    case 'create_quiz':
  1039→      return 'quiz';
  1040→    case 'create_flashcards':
  1041→      return 'flashcards';
  1042→    case 'create_summary':
  1043→    case 'open_student_summary': // #70 maieutic method
  1044→      return 'summary';
  1045→    case 'create_diagram':
  1046→      return 'diagram';
  1047→    case 'create_timeline':
  1048→      return 'timeline';
  1049→    case 'create_demo':
  1050→      return 'demo';
  1051→    default:
  1052→      return null;
  1053→  }
  1054→}
  1055→
  1056→/**
  1057→ * Check if a tool name is a tool creation command.
  1058→ */
  1059→export function isToolCreationCommand(name: string): boolean {
  1060→  return getToolTypeFromName(name) !== null;
  1061→}
  1062→
  1063→// ============================================================================
  1064→// TOOL EXECUTION API
  1065→// ============================================================================
  1066→
  1067→/**
  1068→ * Execute a voice tool command via the API.
  1069→ * This triggers the server-side tool creation and SSE broadcast.
  1070→ */
  1071→export async function executeVoiceTool(
  1072→  sessionId: string,
  1073→  maestroId: string,
  1074→  toolName: string,
  1075→  args: Record<string, unknown>
  1076→): Promise<VoiceToolCallResult> {
  1077→  // Check for mindmap modification commands first
  1078→  if (isMindmapModificationCommand(toolName)) {
  1079→    return executeMindmapModification(sessionId, toolName, args);
  1080→  }
  1081→
  1082→  // Check for summary modification commands (#70 Real-time Summary Tool)
  1083→  if (isSummaryModificationCommand(toolName)) {
  1084→    return executeSummaryModification(sessionId, toolName, args);
  1085→  }
  1086→
  1087→  // Check for onboarding commands (#61 Onboarding Voice Integration)
  1088→  if (isOnboardingCommand(toolName)) {
  1089→    return executeOnboardingTool(toolName, args);
  1090→  }
  1091→
  1092→  const toolType = getToolTypeFromName(toolName);
  1093→
  1094→  // Non-tool commands (web_search, capture_homework) are handled differently
  1095→  if (!toolType) {
  1096→    return { success: true, displayed: false };
  1097→  }
  1098→
  1099→  try {
  1100→    // Call the API to create the tool and broadcast events
  1101→    const response = await fetch('/api/tools/create', {
  1102→      method: 'POST',
  1103→      headers: { 'Content-Type': 'application/json' },
  1104→      body: JSON.stringify({
  1105→        sessionId,
  1106→        maestroId,
  1107→        toolType,
  1108→        title: args.title || args.name || 'Untitled',
  1109→        subject: args.subject,
  1110→        content: args,
  1111→      }),
  1112→    });
  1113→
  1114→    if (!response.ok) {
  1115→      const error = await response.json();
  1116→      return { success: false, error: error.message || 'Failed to create tool' };
  1117→    }
  1118→
  1119→    const result = await response.json();
  1120→    return {
  1121→      success: true,
  1122→      toolId: result.toolId,
  1123→      toolType,
  1124→      displayed: true,
  1125→    };
  1126→  } catch (error) {
  1127→    logger.error('[VoiceToolCommands] Failed to execute tool', { error });
  1128→    return {
  1129→      success: false,
  1130→      error: error instanceof Error ? error.message : 'Unknown error',
  1131→    };
  1132→  }
  1133→}
  1134→
  1135→/**
  1136→ * Execute a mindmap modification command via SSE broadcast.
  1137→ * These commands modify an existing mindmap in real-time.
  1138→ */
  1139→export async function executeMindmapModification(
  1140→  sessionId: string,
  1141→  commandName: string,
  1142→  args: Record<string, unknown>
  1143→): Promise<VoiceToolCallResult> {
  1144→  try {
  1145→    // Send modification event to SSE endpoint
  1146→    const response = await fetch('/api/tools/stream/modify', {
  1147→      method: 'POST',
  1148→      headers: { 'Content-Type': 'application/json' },
  1149→      body: JSON.stringify({
  1150→        sessionId,
  1151→        command: commandName,
  1152→        args,
  1153→      }),
  1154→    });
  1155→
  1156→    if (!response.ok) {
  1157→      const error = await response.json();
  1158→      return {
  1159→        success: false,
  1160→        error: error.message || 'Failed to modify mindmap',
  1161→      };
  1162→    }
  1163→
  1164→    logger.info('[VoiceToolCommands] Mindmap modification sent', { commandName, args });
  1165→    return {
  1166→      success: true,
  1167→      toolType: 'mindmap',
  1168→      displayed: true,
  1169→    };
  1170→  } catch (error) {
  1171→    logger.error('[VoiceToolCommands] Failed to modify mindmap', { error });
  1172→    return {
  1173→      success: false,
  1174→      error: error instanceof Error ? error.message : 'Unknown error',
  1175→    };
  1176→  }
  1177→}
  1178→
  1179→/**
  1180→ * Execute a summary modification command via SSE broadcast.
  1181→ * These commands modify an existing summary in real-time.
  1182→ */
  1183→export async function executeSummaryModification(
  1184→  sessionId: string,
  1185→  commandName: string,
  1186→  args: Record<string, unknown>
  1187→): Promise<VoiceToolCallResult> {
  1188→  try {
  1189→    // Send modification event to SSE endpoint
  1190→    const response = await fetch('/api/tools/stream/modify', {
  1191→      method: 'POST',
  1192→      headers: { 'Content-Type': 'application/json' },
  1193→      body: JSON.stringify({
  1194→        sessionId,
  1195→        toolType: 'summary',
  1196→        command: commandName,
  1197→        args,
  1198→      }),
  1199→    });
  1200→
  1201→    if (!response.ok) {
  1202→      const error = await response.json();
  1203→      return {
  1204→        success: false,
  1205→        error: error.message || 'Failed to modify summary',
  1206→      };
  1207→    }
  1208→
  1209→    logger.info('[VoiceToolCommands] Summary modification sent', { commandName, args });
  1210→    return {
  1211→      success: true,
  1212→      toolType: 'summary',
  1213→      displayed: true,
  1214→    };
  1215→  } catch (error) {
  1216→    logger.error('[VoiceToolCommands] Failed to modify summary', { error });
  1217→    return {
  1218→      success: false,
  1219→      error: error instanceof Error ? error.message : 'Unknown error',
  1220→    };
  1221→  }
  1222→}
  1223→
  1224→/**
  1225→ * Generate a tool ID for a voice command.
  1226→ */
  1227→export function generateToolId(): string {
  1228→  return `voice-tool-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  1229→}
  1230→
  1231→// ============================================================================
  1232→// TOOL INSTRUCTION PROMPTS
  1233→// ============================================================================
  1234→
  1235→/**
  1236→ * Additional instructions for the AI about when to use tools.
  1237→ * Injected into the voice session instructions.
  1238→ */
  1239→export const TOOL_USAGE_INSTRUCTIONS = `
  1240→## STRUMENTI DISPONIBILI
  1241→
  1242→Hai accesso a strumenti per creare materiali didattici. USA questi strumenti quando appropriato:
  1243→
  1244→### Quando usare create_mindmap:
  1245→- Lo studente dice "fammi una mappa", "crea uno schema", "organizza questo argomento"
  1246→- Vuole vedere le connessioni tra concetti
  1247→- Chiede di visualizzare un argomento
  1248→
  1249→### Quando usare create_quiz:
  1250→- Lo studente dice "interrogami", "fammi delle domande", "voglio fare un test"
  1251→- Vuole verificare cosa ha capito
  1252→- Si sta preparando per una verifica
  1253→
  1254→**REGOLA IMPORTANTE PER I QUIZ:**
  1255→Prima di creare un quiz, CHIEDI SEMPRE allo studente: "Preferisci fare il quiz per iscritto, così lo vedi sullo schermo, oppure a voce così te lo faccio io?"
  1256→- Se sceglie **PER ISCRITTO**: usa create_quiz per mostrare le domande sullo schermo
  1257→- Se sceglie **A VOCE**: NON usare create_quiz! Fai tu le domande a voce:
  1258→  1. Leggi la domanda ad alta voce
  1259→  2. Elenca le opzioni (A, B, C, D)
  1260→  3. Aspetta la risposta dello studente
  1261→  4. Conferma se è corretta o spiega perché è sbagliata
  1262→  5. Passa alla domanda successiva
  1263→  6. Alla fine dai un resoconto del punteggio
  1264→
  1265→### Quando usare create_flashcards:
  1266→- Lo studente dice "fammi delle flashcard", "devo memorizzare"
  1267→- Vuole imparare vocaboli, date, formule, definizioni
  1268→- Chiede aiuto per memorizzare
  1269→
  1270→### Quando usare open_student_summary (PREFERITO - metodo maieutico):
  1271→- Lo studente dice "devo fare un riassunto", "devo scrivere un riassunto"
  1272→- Vuole scrivere LUI STESSO il riassunto (compito, esercizio)
  1273→- Apre l'editor vuoto, lo studente scrive, tu guidi con domande
  1274→
  1275→### Quando usare create_summary (solo se lo studente vuole che tu generi):
  1276→- Lo studente dice "riassumimi TU", "fai TU una sintesi"
  1277→- Ha bisogno di un ripasso veloce generato dall'AI
  1278→- Vuole i punti chiave senza scrivere lui stesso
  1279→
  1280→## COMANDI VOCALI PER RIASSUNTI DELLO STUDENTE (metodo maieutico)
  1281→
  1282→### student_summary_add_comment
  1283→- Usa per dare feedback sul testo scritto dallo studente
  1284→- Evidenzia parti specifiche e aggiungi commenti costruttivi
  1285→- Es: "Questo punto potrebbe essere più chiaro" oppure "Ottima osservazione!"
  1286→
  1287→## COMANDI VOCALI PER MODIFICARE RIASSUNTI (legacy)
  1288→
  1289→Quando c'è un riassunto attivo, lo studente può modificarlo vocalmente:
  1290→
  1291→### summary_set_title
  1292→- Imposta il titolo quando lo studente dice l'argomento
  1293→
  1294→### summary_add_section
  1295→- "Parliamo di [argomento]" - crea una nuova sezione
  1296→- "Aggiungi una sezione su [tema]" - nuova sezione
  1297→
  1298→### summary_add_point
  1299→- "Ricorda che..." - aggiunge un punto alla sezione corrente
  1300→- "Un altro punto importante è..." - aggiunge punto
  1301→
  1302→### summary_finalize
  1303→- "Ho finito" - salva e chiude il riassunto
  1304→- "Salva il riassunto" - finalizza
  1305→
  1306→### Quando usare create_diagram:
  1307→- Lo studente chiede un flowchart, un diagramma di flusso
  1308→- Vuole visualizzare un processo o algoritmo
  1309→- Ha bisogno di vedere relazioni (ER diagram)
  1310→
  1311→### Quando usare create_timeline:
  1312→- Lo studente studia storia e chiede una linea del tempo
  1313→- Vuole ordinare eventi cronologicamente
  1314→- Ha bisogno di visualizzare sequenze storiche
  1315→
  1316→### Quando usare capture_homework:
  1317→- Lo studente ha un esercizio scritto e ha bisogno di aiuto
  1318→- Dice "ti faccio vedere", "guarda questo problema"
  1319→- Ha difficoltà con un compito specifico
  1320→
  1321→### Quando usare search_archive:
  1322→- Lo studente chiede di materiali creati in precedenza
  1323→- Dice "hai salvato quella mappa?", "rivediamo il quiz di storia"
  1324→- Vuole recuperare contenuti già creati (mappe, quiz, flashcard, riassunti, demo, compiti)
  1325→- Usa per trovare materiali per argomento, materia, o tipo
  1326→
  1327→## COMANDI VOCALI PER MODIFICARE MAPPE MENTALI
  1328→
  1329→Quando c'è una mappa mentale attiva, lo studente può modificarla vocalmente:
  1330→
  1331→### mindmap_add_node
  1332→- "Aggiungi [concetto]" - aggiunge un nuovo nodo
  1333→- "Metti anche [concetto]" - aggiunge un nodo collegato
  1334→- "Inserisci [concetto] sotto [nodo]" - aggiunge figlio specifico
  1335→
  1336→### mindmap_connect_nodes
  1337→- "Collega [A] con [B]" - crea connessione tra due nodi
  1338→- "Unisci [A] e [B]" - collega i nodi
  1339→
  1340→### mindmap_expand_node
  1341→- "Espandi [nodo]" - genera sotto-nodi automaticamente
  1342→- "Approfondisci [nodo]" - aggiunge dettagli
  1343→
  1344→### mindmap_delete_node
  1345→- "Cancella [nodo]" - rimuove il nodo
  1346→- "Togli [nodo]" - elimina dalla mappa
  1347→
  1348→### mindmap_focus_node
  1349→- "Vai a [nodo]" - centra la vista su quel nodo
  1350→- "Mostrami [nodo]" - zoom su nodo specifico
  1351→
  1352→### mindmap_set_color
  1353→- "Colora [nodo] di rosso/blu/verde" - cambia colore
  1354→- "Fai [nodo] giallo" - imposta colore
  1355→
  1356→NOTA: Quando crei uno strumento, ANNUNCIALO prima vocalmente (es. "Ti preparo un quiz su questo argomento...") e poi invoca la funzione.
  1357→`;
