     3→import { useEffect, useRef, useState, useCallback } from 'react';
     4→import { motion } from 'framer-motion';
     5→import { Markmap } from 'markmap-view';
     6→import { Transformer } from 'markmap-lib';
     7→import { Printer, Download, ZoomIn, ZoomOut, Accessibility, RotateCcw, Maximize, Minimize } from 'lucide-react';
     8→import { cn } from '@/lib/utils';
     9→import { logger } from '@/lib/logger';
    10→import { useAccessibilityStore } from '@/lib/accessibility/accessibility-store';
    11→
    12→// Node structure for programmatic mindmap creation
    13→export interface MindmapNode {
    14→  id: string;
    15→  label: string;
    16→  children?: MindmapNode[];
    17→  icon?: string;
    18→  color?: string;
    19→}
    20→
    21→// Props can accept either markdown string OR structured nodes
    22→export interface MarkMapRendererProps {
    23→  title: string;
    24→  markdown?: string;
    25→  nodes?: MindmapNode[];
    26→  className?: string;
    27→}
    28→
    29→// Transformer instance for markdown parsing
    30→const transformer = new Transformer();
    31→
    32→// Convert structured nodes to markdown format
    33→function nodesToMarkdown(nodes: MindmapNode[], title: string): string {
    34→  const buildMarkdown = (node: MindmapNode, depth: number): string => {
    35→    const prefix = '#'.repeat(depth + 1);
    36→    let result = `${prefix} ${node.label}\n`;
    37→
    38→    if (node.children && node.children.length > 0) {
    39→      for (const child of node.children) {
    40→        result += buildMarkdown(child, depth + 1);
    41→      }
    42→    }
    43→
    44→    return result;
    45→  };
    46→
    47→  let markdown = `# ${title}\n`;
    48→  for (const node of nodes) {
    49→    markdown += buildMarkdown(node, 1);
    50→  }
    51→
    52→  return markdown;
    53→}
    54→
    55→export function MarkMapRenderer({ title, markdown, nodes, className }: MarkMapRendererProps) {
    56→  const svgRef = useRef<SVGSVGElement>(null);
    57→  const containerRef = useRef<HTMLDivElement>(null);
    58→  const markmapRef = useRef<Markmap | null>(null);
    59→  const [error, setError] = useState<string | null>(null);
    60→  const [rendered, setRendered] = useState(false);
    61→  const [zoom, setZoom] = useState(1);
    62→  const [accessibilityMode, setAccessibilityMode] = useState(false);
    63→  const [isFullscreen, setIsFullscreen] = useState(false);
    64→
    65→  const { settings } = useAccessibilityStore();
    66→
    67→  // Get the markdown content
    68→  const getMarkdownContent = useCallback((): string => {
    69→    if (markdown) {
    70→      return markdown;
    71→    }
    72→    if (nodes && nodes.length > 0) {
    73→      return nodesToMarkdown(nodes, title);
    74→    }
    75→    return `# ${title}\n## No content`;
    76→  }, [markdown, nodes, title]);
    77→
    78→  // Generate accessible description
    79→  const generateTextDescription = useCallback((): string => {
    80→    if (nodes && nodes.length > 0) {
    81→      const describeNode = (node: MindmapNode): string => {
    82→        let desc = node.label;
    83→        if (node.children && node.children.length > 0) {
    84→          desc += ': ' + node.children.map(c => describeNode(c)).join(', ');
    85→        }
    86→        return desc;
    87→      };
    88→      return `${title} con i seguenti rami: ${nodes.map(n => describeNode(n)).join('; ')}`;
    89→    }
    90→    return `Mappa mentale: ${title}`;
    91→  }, [nodes, title]);
    92→
    93→  // Render mindmap
    94→  useEffect(() => {
    95→    const renderMindmap = async () => {
    96→      if (!svgRef.current) return;
    97→
    98→      try {
    99→        setError(null);
   100→        setRendered(false);
   101→
   102→        // Clear previous content
   103→        svgRef.current.innerHTML = '';
   104→
   105→        // Get markdown and transform to markmap data
   106→        const content = getMarkdownContent();
   107→        const { root } = transformer.transform(content);
   108→
   109→        // Determine font family based on accessibility settings
   110→        const fontFamily = settings.dyslexiaFont || accessibilityMode
   111→          ? 'OpenDyslexic, Comic Sans MS, sans-serif'
   112→          : 'Arial, Helvetica, sans-serif';
   113→
   114→        // Determine colors based on accessibility settings
   115→        const isHighContrast = settings.highContrast || accessibilityMode;
   116→
   117→        // Create or update markmap
   118→        if (markmapRef.current) {
   119→          markmapRef.current.destroy();
   120→        }
   121→
   122→        markmapRef.current = Markmap.create(svgRef.current, {
   123→          autoFit: true,
   124→          duration: 300,
   125→          maxWidth: 280,
   126→          paddingX: 16,
   127→          spacingVertical: 8,
   128→          spacingHorizontal: 100,
   129→          initialExpandLevel: 3, // Start with first 3 levels expanded, rest collapsed
   130→          zoom: true, // Enable zoom/pan
   131→          pan: true,  // Enable panning
   132→          color: (node) => {
   133→            if (isHighContrast) {
   134→              // High contrast colors
   135→              const colors = ['#ffff00', '#00ffff', '#ff00ff', '#00ff00', '#ff8000'];
   136→              return colors[node.state?.depth % colors.length] || '#ffffff';
   137→            }
   138→            // Normal theme colors
   139→            const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];
   140→            return colors[node.state?.depth % colors.length] || '#64748b';
   141→          },
   142→        }, root);
   143→
   144→        // Apply custom styles after render
   145→        setTimeout(() => {
   146→          if (svgRef.current) {
   147→            // Apply font to all text elements
   148→            const textElements = svgRef.current.querySelectorAll('text, foreignObject');
   149→            textElements.forEach((el) => {
   150→              if (el instanceof SVGElement || el instanceof HTMLElement) {
   151→                el.style.fontFamily = fontFamily;
   152→                if (settings.largeText) {
   153→                  el.style.fontSize = '16px';
   154→                }
   155→              }
   156→            });
   157→
   158→            // High contrast background
   159→            if (isHighContrast) {
   160→              const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
   161→              rect.setAttribute('width', '100%');
   162→              rect.setAttribute('height', '100%');
   163→              rect.setAttribute('fill', '#000000');
   164→              svgRef.current.insertBefore(rect, svgRef.current.firstChild);
   165→            }
   166→          }
   167→        }, 100);
   168→
   169→        // Add ARIA attributes
   170→        svgRef.current.setAttribute('role', 'img');
   171→        svgRef.current.setAttribute('aria-label', `Mappa mentale: ${title}`);
   172→
   173→        // Add title and desc for screen readers
   174→        const titleEl = document.createElementNS('http://www.w3.org/2000/svg', 'title');
   175→        titleEl.textContent = `Mappa mentale: ${title}`;
   176→        svgRef.current.insertBefore(titleEl, svgRef.current.firstChild);
   177→
   178→        const descEl = document.createElementNS('http://www.w3.org/2000/svg', 'desc');
   179→        descEl.textContent = generateTextDescription();
   180→        svgRef.current.insertBefore(descEl, svgRef.current.firstChild?.nextSibling || null);
   181→
   182→        setRendered(true);
   183→      } catch (err) {
   184→        const errorMsg = err instanceof Error ? err.message : String(err);
   185→        setError(errorMsg);
   186→        logger.error('MarkMap render error', { error: String(err) });
   187→      }
   188→    };
   189→
   190→    renderMindmap();
   191→  }, [markdown, nodes, title, settings.dyslexiaFont, settings.highContrast, settings.largeText, accessibilityMode, getMarkdownContent, generateTextDescription]);
   192→
   193→  // Zoom controls
   194→  const handleZoomIn = useCallback(() => {
   195→    if (markmapRef.current) {
   196→      markmapRef.current.rescale(1.25);
   197→    }
   198→    setZoom(z => Math.min(z * 1.25, 3));
   199→  }, []);
   200→
   201→  const handleZoomOut = useCallback(() => {
   202→    if (markmapRef.current) {
   203→      markmapRef.current.rescale(0.8);
   204→    }
   205→    setZoom(z => Math.max(z * 0.8, 0.5));
   206→  }, []);
   207→
   208→  const handleReset = useCallback(() => {
   209→    if (markmapRef.current) {
   210→      markmapRef.current.fit();
   211→    }
   212→    setZoom(1);
   213→  }, []);
   214→
   215→  // Fullscreen toggle
   216→  const handleFullscreen = useCallback(async () => {
   217→    if (!containerRef.current) return;
   218→
   219→    try {
   220→      if (!document.fullscreenElement) {
   221→        await containerRef.current.requestFullscreen();
   222→        setIsFullscreen(true);
   223→      } else {
   224→        await document.exitFullscreen();
   225→        setIsFullscreen(false);
   226→      }
   227→    } catch (err) {
   228→      logger.error('Fullscreen error', { error: String(err) });
   229→    }
   230→  }, []);
   231→
   232→  // Listen for fullscreen changes (user may exit with Escape)
   233→  useEffect(() => {
   234→    const handleFullscreenChange = () => {
   235→      setIsFullscreen(!!document.fullscreenElement);
   236→      // Re-fit the mindmap when entering/exiting fullscreen
   237→      if (markmapRef.current) {
   238→        setTimeout(() => markmapRef.current?.fit(), 100);
   239→      }
   240→    };
   241→
   242→    document.addEventListener('fullscreenchange', handleFullscreenChange);
   243→    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
   244→  }, []);
   245→
   246→  // Print functionality - expands labels to prevent truncation
   247→  const handlePrint = useCallback(() => {
   248→    if (!svgRef.current) return;
   249→
   250→    const printWindow = window.open('', '_blank');
   251→    if (!printWindow) return;
   252→
