// Get default user ID - will be replaced by proper auth
function getUserId(): string {
  // In production, this would come from auth context
  // For now, use a session-based ID
  if (typeof window === 'undefined') return 'default-user';

  let userId = sessionStorage.getItem('convergio-user-id');
  if (!userId) {
    userId = `user-${crypto.randomUUID()}`;
    sessionStorage.setItem('convergio-user-id', userId);
  }
  return userId;
}

/**
 * Fetch materials from API
 */
async function fetchMaterials(
  toolType: ToolType,
  userId: string
): Promise<SavedMaterial[]> {
  try {
    const response = await fetch(
      `/api/materials?userId=${userId}&toolType=${toolType}&status=active`
    );
    if (!response.ok) {
      throw new Error(`API error: ${response.status}`);
    }
    const data = await response.json();
    return data.materials || [];
  } catch (error) {
    logger.error('Failed to fetch materials', { error, toolType });
    return [];
  }
}

/**
 * Save material to API
 */
async function saveMaterialToAPI(
  userId: string,
  toolType: ToolType,
  title: string,
  content: Record<string, unknown>,
  options?: {
    subject?: string;
    maestroId?: string;
    preview?: string;
  }
): Promise<SavedMaterial | null> {
  try {
    const toolId = crypto.randomUUID();
    const response = await fetch('/api/materials', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        userId,
        toolId,
        toolType,
        title,
        content,
        ...options,
      }),
    });
    if (!response.ok) {
      throw new Error(`API error: ${response.status}`);
    }
    const data = await response.json();
    return data.material;
  } catch (error) {
    logger.error('Failed to save material', { error, toolType, title });
    return null;
  }
}

/**
 * Delete material via API
 */
async function deleteMaterialFromAPI(toolId: string): Promise<boolean> {
  try {
    const response = await fetch(`/api/materials?toolId=${toolId}`, {
      method: 'DELETE',
    });
    return response.ok;
  } catch (error) {
    logger.error('Failed to delete material', { error, toolId });
    return false;
  }
}

/**
 * Update material via API
 */
async function updateMaterialInAPI(
  toolId: string,
  content: Record<string, unknown>,
  title?: string
): Promise<boolean> {
  try {
    const response = await fetch('/api/materials', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ toolId, content, title }),
    });
    return response.ok;
  } catch (error) {
    logger.error('Failed to update material', { error, toolId });
    return false;
  }
}

/**
 * Hook for mindmaps
 */
export function useMindmaps() {
  const [mindmaps, setMindmaps] = useState<SavedMindmap[]>([]);
  const [loading, setLoading] = useState(true);
  const userId = getUserId();

  // Load mindmaps from API
  const loadMindmaps = useCallback(async () => {
    setLoading(true);
    const materials = await fetchMaterials('mindmap', userId);
    const mapped: SavedMindmap[] = materials.map((m) => ({
      id: m.toolId,
      title: m.title,
      nodes: (m.content as { nodes?: MindmapNode[] }).nodes || [],
      subject: (m.subject || 'general') as Subject,
      createdAt: new Date(m.createdAt),
      maestroId: m.maestroId,
    }));
    setMindmaps(mapped);
    setLoading(false);
  }, [userId]);

  /* eslint-disable react-hooks/set-state-in-effect */
  useEffect(() => {
    loadMindmaps();
  }, [loadMindmaps]);
  /* eslint-enable react-hooks/set-state-in-effect */

  // Save mindmap
  const saveMindmap = useCallback(
    async (mindmap: Omit<SavedMindmap, 'id' | 'createdAt'>) => {
      const saved = await saveMaterialToAPI(
        userId,
        'mindmap',
        mindmap.title,
        { nodes: mindmap.nodes },
        { subject: mindmap.subject, maestroId: mindmap.maestroId }
      );
      if (saved) {
        await loadMindmaps();
      }
      return saved;
    },
    [userId, loadMindmaps]
  );

  // Delete mindmap
  const deleteMindmap = useCallback(
    async (id: string) => {
      const success = await deleteMaterialFromAPI(id);
      if (success) {
        setMindmaps((prev) => prev.filter((m) => m.id !== id));
      }
      return success;
    },
    []
  );

  return { mindmaps, loading, saveMindmap, deleteMindmap, reload: loadMindmaps };
}

/**
 * Hook for quizzes
 */
export function useQuizzes() {
  const [quizzes, setQuizzes] = useState<SavedQuiz[]>([]);
  const [loading, setLoading] = useState(true);
  const userId = getUserId();

  const loadQuizzes = useCallback(async () => {
    setLoading(true);
    const materials = await fetchMaterials('quiz', userId);
    const mapped: SavedQuiz[] = materials.map((m) => ({
      id: m.toolId,
      title: m.title,
      subject: m.subject || '',
      questions: (m.content as { questions?: QuizQuestion[] }).questions || [],
      createdAt: new Date(m.createdAt),
    }));
    setQuizzes(mapped);
    setLoading(false);
  }, [userId]);

  /* eslint-disable react-hooks/set-state-in-effect */
  useEffect(() => {
    loadQuizzes();
  }, [loadQuizzes]);

/**
 * ConvergioEdu Intent Detection System
 *
 * Analyzes student messages to determine:
 * 1. What the student needs (subject help, method help, emotional support)
 * 2. Who should respond (Maestro, Coach, Buddy)
 *
 * Part of the Support Triangle routing system.
 * Related: #24 MirrorBuddy Issue, ManifestoEdu.md
 */

import type { Subject, CharacterType } from '@/types';

// ============================================================================
// TYPES
// ============================================================================

/**
 * Detected intent from student message.
 */
export interface DetectedIntent {
  /** Primary intent type */
  type: IntentType;
  /** Confidence score (0-1) */
  confidence: number;
  /** Detected subject if academic */
  subject?: Subject;
  /** Detected topic within subject */
  topic?: string;
  /** Emotional indicators if any */
  emotionalIndicators?: EmotionalIndicator[];
  /** Recommended character to respond */
  recommendedCharacter: CharacterType;
  /** Reason for recommendation */
  reason: string;
  /** Tool type if tool_request intent */
  toolType?: ToolType;
}

/**
 * Intent types that can be detected.
 */
export type IntentType =
  | 'academic_help' // Needs subject explanation
  | 'method_help' // Needs study method/organization help
  | 'emotional_support' // Needs peer support/validation
  | 'crisis' // Urgent emotional distress
  | 'general_chat' // Casual conversation
  | 'tool_request' // Wants to create flashcards, mindmaps, etc.
  | 'tech_support'; // Needs help with app features/configuration (Issue #16)

/**
 * Tool types that can be created via conversation.
 */
export type ToolType = 'mindmap' | 'quiz' | 'flashcard' | 'demo';

/**
 * Emotional indicators detected in message.
 */
export type EmotionalIndicator =
  | 'frustration'
  | 'anxiety'
  | 'sadness'
  | 'loneliness'
  | 'overwhelm'
  | 'confusion'
  | 'excitement'
  | 'curiosity';

