/**
 * ConvergioEdu Character Router
 *
 * Routes students to the appropriate character based on:
 * 1. Detected intent (academic, method, emotional)
 * 2. Student preferences (preferred coach/buddy gender)
 * 3. Subject matter (for Maestro selection)
 *
 * This is the orchestration layer of the Support Triangle.
 * Related: #24 MirrorBuddy Issue, ManifestoEdu.md
 */

import type {
  Subject,
  CharacterType,
  SupportTeacher,
  BuddyProfile,
  ExtendedStudentProfile,
  SupportCharacter,
} from '@/types';
import type { MaestroFull } from '@/data/maestri';
import { getMaestroById, getMaestriBySubject } from '@/data/maestri';
import {
  getSupportTeacherById,
  getDefaultSupportTeacher,
} from '@/data/support-teachers';
import {
  getBuddyById,
  getDefaultBuddy,
  type BuddyId,
} from '@/data/buddy-profiles';
import { detectIntent, type DetectedIntent } from './intent-detection';
import { injectSafetyGuardrails } from '@/lib/safety';

// ============================================================================
// TYPES
// ============================================================================

/**
 * Result of character routing.
 */
export interface RoutingResult {
  /** The character type selected */
  characterType: CharacterType;
  /** The specific character to use */
  character: MaestroFull | SupportTeacher | BuddyProfile;
  /** The intent that led to this routing */
  intent: DetectedIntent;
  /** Why this character was selected */
  reason: string;
  /** Alternative characters that could also help */
  alternatives?: Array<{
    character: MaestroFull | SupportTeacher | BuddyProfile;
    reason: string;
  }>;
}

/**
 * Student context for routing decisions.
 */
export interface RoutingContext {
  /** The student's message to route */
  message: string;
  /** The student's profile with preferences */
  studentProfile: ExtendedStudentProfile;
  /** Currently active character (for conversation continuity) */
  currentCharacter?: {
    type: CharacterType;
    id: string;
  };
  /** Whether to prefer continuity over optimal routing */
  preferContinuity?: boolean;
}

// ============================================================================
// SUBJECT TO MAESTRO MAPPING
// ============================================================================

/**
 * Default Maestro IDs for each subject.
 * These are the "primary" Maestri for each subject.
 */
const DEFAULT_MAESTRO_BY_SUBJECT: Record<Subject, string> = {
  mathematics: 'euclide-matematica',
  physics: 'feynman-fisica',
  chemistry: 'curie-chimica',
  biology: 'darwin-biologia', // Fallback will find actual maestro if exists
  history: 'erodoto-storia',
  geography: 'humboldt-geografia',
  italian: 'manzoni-italiano',
  english: 'shakespeare-inglese',
  art: 'leonardo-arte',
  music: 'mozart-musica',
  civics: 'montessori-civica', // Fallback will find actual maestro if exists
  economics: 'smith-economia',
  computerScience: 'turing-informatica', // Fallback will find actual maestro if exists
  health: 'ippocrate-salute', // Fallback will find actual maestro if exists
  philosophy: 'socrate-filosofia',
  internationalLaw: 'grozio-diritto', // Fallback will find actual maestro if exists
};

// ============================================================================
// ROUTING FUNCTIONS
// ============================================================================

/**
 * Gets the appropriate Maestro for a subject.
 */
function getMaestroForSubject(subject: Subject): MaestroFull | undefined {
  const defaultId = DEFAULT_MAESTRO_BY_SUBJECT[subject];
  if (defaultId) {
    const maestro = getMaestroById(defaultId);
    if (maestro) return maestro;
  }

  // Fallback: get first Maestro for this subject
  const maestri = getMaestriBySubject(subject);
  return maestri[0];
}

/**
 * Gets the appropriate Coach based on student preferences.
 */
function getCoachForStudent(profile: ExtendedStudentProfile): SupportTeacher {
  if (profile.preferredCoach) {
    const preferred = getSupportTeacherById(profile.preferredCoach);
    if (preferred) {
      return preferred;
    }
  }

  // No preference: use default (Melissa)
  return getDefaultSupportTeacher();
}

/**
 * Gets the appropriate Buddy based on student preferences.
 */
export function getBuddyForStudent(profile: ExtendedStudentProfile): BuddyProfile {
  if (profile.preferredBuddy) {
    const preferred = getBuddyById(profile.preferredBuddy);
    if (preferred) {
      return preferred;
    }
  }

  // No preference: use default (Mario)
  return getDefaultBuddy();
}

/**
 * ConvergioEdu Handoff Manager
 *
 * Manages character handoffs during conversations.
 * Detects when a character should suggest switching to another,
 * and orchestrates the handoff flow.
 *
 * Part of I-05: Handoff Between Characters
 * Related: #23 Conversation-First Architecture
 */

import type {
  CharacterType,
  ExtendedStudentProfile,
  SupportTeacher,
  BuddyProfile,
} from '@/types';
import type { MaestroFull } from '@/data/maestri';
import type { ActiveCharacter, HandoffSuggestion } from '@/lib/stores/conversation-flow-store';
// Note: routeToCharacter, suggestCharacterSwitch, getCharacterGreeting available from character-router if needed
import { detectIntent, type IntentType } from './intent-detection';
import {
  getSupportTeacherById,
  getDefaultSupportTeacher,
} from '@/data/support-teachers';
import { getBuddyById, getDefaultBuddy } from '@/data/buddy-profiles';
import { getMaestroById, getMaestriBySubject } from '@/data/maestri';

// ============================================================================
// TYPES
// ============================================================================

/**
 * Context for handoff analysis.
 */
export interface HandoffContext {
  /** Current message from student */
  message: string;
  /** AI response that may contain handoff signals */
  aiResponse?: string;
  /** Currently active character */
  activeCharacter: ActiveCharacter;
  /** Student profile */
  studentProfile: ExtendedStudentProfile;
  /** Recent messages for context (last 5) */
  recentMessages?: Array<{ role: 'user' | 'assistant'; content: string }>;
}

/**
 * Result of handoff analysis.
 */
export interface HandoffAnalysis {
  /** Whether a handoff is recommended */
  shouldHandoff: boolean;
  /** The handoff suggestion if applicable */
  suggestion?: HandoffSuggestion;
  /** Confidence level (0-1) */
  confidence: number;
  /** Reason for the recommendation */
  reason: string;
}

/**
 * Handoff triggers that can be detected in AI responses.
 */
export type HandoffTrigger =
  | 'explicit_suggestion' // AI explicitly suggests another character
  | 'subject_mismatch' // Student asking about a different subject
  | 'emotional_need' // Student showing emotional distress
  | 'method_need' // Student needs study method help
  | 'stuck_pattern' // Conversation is stuck, need different approach
  | 'crisis_detected' // Crisis situation requiring buddy
  | 'academic_deep_dive'; // Need subject expert for deep content

// ============================================================================
// HANDOFF SIGNAL PATTERNS
// ============================================================================

/**
 * Patterns in AI responses that signal a handoff suggestion.
 */
const HANDOFF_SIGNAL_PATTERNS = {
  // Coach suggesting a Maestro
  maestro_suggestion: [
    /(?:ti consiglio|potresti parlare con|c'è|chiedi a|il (?:professor|maestro))\s+(\w+)/i,
    /per (?:questa materia|questo argomento).*?(?:meglio|ideale|perfetto)\s+(\w+)/i,
    /(?:euclide|feynman|manzoni|leonardo|shakespeare|curie|socrate|mozart|erodoto|humboldt|smith)/i,
  ],
  // Coach or Maestro suggesting Buddy for emotional support
  buddy_suggestion: [
    /(?:capisco che|sembra che).*?(?:difficile|stressante|preoccupato|ansioso)/i,
    /(?:mario|faty).*?(?:può aiutarti|ti capisce|può ascoltarti)/i,
    /(?:vuoi parlare con|potresti sentirti meglio parlando con).*?(?:un amico|qualcuno della tua età)/i,
  ],
  // Buddy suggesting Coach for method help
  coach_suggestion: [
    /(?:melissa|roberto).*?(?:può aiutarti|sa come|organizzare)/i,
    /(?:per organizzarti|per il metodo|per pianificare).*?(?:chiedi a|parla con)/i,
  ],
  // Anyone detecting emotional crisis
  crisis_signals: [
    /(?:mi sento|sono)\s+(?:molto\s+)?(?:solo|triste|disperato|senza speranza)/i,
    /non ce la faccio più/i,
    /nessuno mi capisce/i,
    /voglio smettere/i,
  ],
};

/**
 * Intent patterns that suggest handoff.
 */
const INTENT_HANDOFF_MAP: Record<IntentType, CharacterType | null> = {
  academic_help: 'maestro',
  method_help: 'coach',
  emotional_support: 'buddy',
  crisis: 'buddy',
  tool_request: null, // Stay with current
  general_chat: null, // Stay with current
  tech_support: 'coach', // Issue #16: Coach handles platform questions
};

// ============================================================================
// ANALYSIS FUNCTIONS
// ============================================================================

/**
 * Analyzes whether a handoff should occur.
 */
export function analyzeHandoff(context: HandoffContext): HandoffAnalysis {
  const { message, aiResponse, activeCharacter, studentProfile } = context;

  // 1. Check for explicit handoff signals in AI response
  if (aiResponse) {
    const explicitHandoff = detectExplicitHandoff(aiResponse, activeCharacter, studentProfile);
    if (explicitHandoff.shouldHandoff) {
      return explicitHandoff;
    }
  }

  // 2. Check message intent vs current character
  const intent = detectIntent(message);
  const intentMismatch = checkIntentMismatch(intent.type, activeCharacter.type, studentProfile);
  if (intentMismatch.shouldHandoff) {
    return intentMismatch;
  }

  // 3. Check for crisis signals
  const crisisCheck = detectCrisisSignals(message, aiResponse || '');
  if (crisisCheck.shouldHandoff) {
    return crisisCheck;

